import{_ as a,o as t,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Manage Account Profile","description":"","frontmatter":{"title":"Manage Account Profile","slug":"profile-settings"},"headers":[],"relativePath":"account-hub/profile-settings.md","filePath":"account-hub/profile-settings.md"}'),r={name:"account-hub/profile-settings.md"};function i(s,e,l,c,h,p){return t(),o("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Profile tab on the Account Settings page is where you find your Branch key and secret, app name, app ID, and timezone.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>The Profile tab is part of the <a href="./branch-dashboard-overview.html">legacy Branch</a> experience and is slated for deprecation.</p><p>In the <a href="./new-branch-overview.html">new version</a> of Branch:</p><ul><li>App name, app ID, app logo (social media preview), timezone, and currency settings live on the <a href="./general-new.html">General page</a>.</li><li>Branch Key, Branch Secret, and Access Token live on the Security and Access page, in the <a href="./credentials-new.html">Credentials tab</a>.</li></ul></div><h2 id="branch-key-and-secret" tabindex="-1">Branch Key and Secret <a class="header-anchor" href="#branch-key-and-secret" aria-label="Permalink to &quot;Branch Key and Secret&quot;">​</a></h2><p>In this section, you can access and copy your Branch Keys. Your keys are specific to an app. If you don&#39;t see this option on your view that means you are in <a href="./entity-views-access-controls-overview.html#organization-view">Organization View</a>. Select the menu dropdown to toggle to <a href="./entity-views-access-controls-overview.html#app-view">App View</a>. You will only be able to see your Secret Key if you are an admin.</p><div class="tip custom-block"><p class="custom-block-title">Required Permissions</p><p>You&#39;ll need Admin access to see this page.</p></div><h3 id="reset-branch-key-and-secret" tabindex="-1">Reset Branch Key and Secret <a class="header-anchor" href="#reset-branch-key-and-secret" aria-label="Permalink to &quot;Reset Branch Key and Secret&quot;">​</a></h3><p>If you need to reset your Branch Key/Secret, you will need to be an Admin, or have edit access for App-Level or Organization Level settings. If you have the necessary permissions, you can reset your key by:</p><ol><li>Go to the <strong>Account Settings</strong> page and click the <a href="https://dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Profile tab</a>.</li><li>Here you can copy and/or reset your Branch Key and Secret. By resetting your Key/Secret, we automatically generate a new Key/Secret.</li></ol><h2 id="app-name-and-id-organization-name-and-id" tabindex="-1">App Name and ID &amp; Organization Name and ID <a class="header-anchor" href="#app-name-and-id-organization-name-and-id" aria-label="Permalink to &quot;App Name and ID &amp; Organization Name and ID&quot;">​</a></h2><p>Under the <strong>About Your App</strong>, you can access:</p><ul><li><strong>Organization / App Name</strong> - This is provided by you, and can be changed.</li><li><strong>Organization / App ID</strong> - This is assigned by Branch and cannot be changed.</li></ul><h2 id="dashboard-analytics-time-zone" tabindex="-1">Dashboard Analytics Time Zone <a class="header-anchor" href="#dashboard-analytics-time-zone" aria-label="Permalink to &quot;Dashboard Analytics Time Zone&quot;">​</a></h2><p>The dashboard&#39;s time zone ensures that data in the Branch dashboard is always presented consistently, no matter where in the world you may be when viewing your data. International teams can settle upon a fixed time zone and see Branch data in that time zone.</p><p>The time zone setting also allows you to import data from third parties, like Facebook and Google, and ensure that Branch data matches up with external sources.</p><h3 id="setting-or-changing-timezone" tabindex="-1">Setting Or Changing Timezone <a class="header-anchor" href="#setting-or-changing-timezone" aria-label="Permalink to &quot;Setting Or Changing Timezone&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Warning: Data Discrepancies When Changing Your Time Zone Settings</p><p>Branch allows you to change your time zone. Changing your time zone will take effect after a page refresh, and will set your dashboard to use your new time zone. We do not recommend changing the time zone unless you have to as it can cause discrepancies between previously exported data and the data in your dashboard.</p></div><ol><li>Go to the <a href="https://branch.dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Account Settings</a> page. On the profile tab, find the section <strong>Time Zone</strong>.</li><li>Select your time zone from the dropdown.</li><li>Click <strong>Save Settings</strong>.</li><li>Refresh your browser to see the time zone change take effect.</li></ol><h2 id="delete-app-from-branch-dashboard" tabindex="-1">Delete App from Branch Dashboard <a class="header-anchor" href="#delete-app-from-branch-dashboard" aria-label="Permalink to &quot;Delete App from Branch Dashboard&quot;">​</a></h2><p>Navigate to <a href="https://dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Account Settings</a>, on the <a href="https://dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Profile</a> tab, click <strong>Delete Your App</strong>, and follow the prompts to complete this action. This will be a permanent change. Note the following actions will apply once you delete your Branch app:</p><ul><li>We delete the dashboard user data of the original app creator associated with that particular app. They can still log in to other apps.</li><li>Your links will show a 404.</li><li>All requests to our API (via the SDK), will return a server error.</li><li>Attribution and analytics information will no longer be tracked.</li><li>All data feed systems will stop sending data (such as webhooks and data integrations).</li><li>All Active Subscriptions for the app will be Cancelled.</li></ul><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>Why am I not able to see my app in Branch?</summary><p>If you are unable to see a Branch app that you previously had access to in the Branch app selector, try the following troubleshooting steps:</p><ol><li>If this app is un-named it will not show up on the App selector. You can however search for this app using the App ID on the App selector. This will show up as &#39;Unnamed App&#39; when searched with the App ID.</li><li>Make sure you still have access to this app. Check with an Admin of the app to confirm you are still part of the App team in Branch.</li></ol></details><details><summary>Is there a limit on the number of apps a user can create?</summary><p>Yes, a user account can create a maximum of 100 Branch apps in Branch. If you have a requirement to create more apps, please reach out to us with a description of your use case for creating these apps and our team will review and increase the limit if applicable.</p></details><details><summary>How do I find my Branch App ID?</summary><p>You can find your Branch App ID by logging on to your Branch <a href="https://dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Dashboard</a>.</p><p>Navigate to <strong>Settings</strong> → <strong>Profile</strong> → <strong>About your app</strong> to find the App ID associated with the Branch App.</p><p>If you have an Agency account with Branch, please make sure you select the right advertiser app from the App selection drop-down before navigating to the Account Settings page.</p></details><details><summary>Why can’t I log in to Branch?</summary><p>You should have received an invitation email to log into the Branch Dashboard. If you already have an account registered to your email address, you can also try filling out the <a href="https://dashboard.branch.io/reset" target="_blank" rel="noreferrer">password reset form</a>.</p><p><strong>Note</strong>: Check both your inbox and spam folder for any invitation or password reset links.</p></details>',26)])])}const g=a(r,[["render",i]]);export{u as __pageData,g as default};
